import request from '@/utils/request'
import { SMS_SCENE } from '@/store'

// 认证相关的核心功能
export const auth = {
  // 密码登录
  loginWithPassword: (data) => {
    return request.post('/api/v1/users/auth/login/password/', data)
  },

  // 退出登录
  logout: () => {
    const refreshToken = localStorage.getItem('refresh_token')
    if (!refreshToken) return
    return request.post('/api/v1/users/auth/logout/', { refresh: refreshToken })
  },

  // 刷新 token
  refreshToken: (data) => {
    return request.post('/api/v1/users/auth/token/refresh/', data)
  }
}
